class CartItem:
    def __init__(self, item_id, price):
        self.item_id = item_id
        self.price = price

class CheckOutProcess:
    
    def __init__(self, user_role='user', discount_code=None):
        self.cart_items = []
        self.total = 0
        self.discounted_amount = 0
        self.taxes = 0
        self.final_price = 0
        self.user_role = user_role
        self.discount_code = discount_code
        
    def add_to_cart(self, item):
        if isinstance(item, CartItem):
            self.cart_items.append(item)
            
    def calculate_total(self):
        for cart_item in self.cart_items:
            self.total += cart_item.price
        
    def apply_discounts(self):
        if not self.validate_user():
            return False
        discount = self.get_discount()
        self.discounted_amount = self.total * (1 - discount)
    
    def validate_user(self):
        # Validate user permissions here, for simplicity we assume all users have permission to use discounts except admin
        return self.user_role != 'admin'
        
    def get_discount(self):
        if self.validate_user():
            if self.discount_code == 'SPECIAL10': # 10% discount for all users
                return 0.10
            elif self.discount_code == 'ADMIN20': # Admin gets a 20% discount, but only if he's an admin
                return 0.20 if self.user_role == 'admin' else 0
        return 0
        
    def calculate_taxes(self):
        # Assuming tax rate is 5% for all items in the cart
        self.taxes = (self.discounted_amount or self.total) * 0.05
    
    def process_payment(self, amount):
        if amount >= (self.final_price or self.total + self.taxes):
            return True # Payment processed successfully
        
    def create_order(self):
        pass # Create order record here
       
